def _source_category(src: Optional[str]) -> str:
    """Group tracking sources into coarse categories for UI / change detection."""
    if not src:
        return "unknown"
    if src.startswith("real"):
        return "real"
    if src == "interpolated":
        return "interpolated"
    return "simulated"


