def _carfax_clean(d: Dict[str, Any]) -> Dict[str, Any]:
    d.pop("_id", None)
    return d


async def _carfax_customer_name(customer_id: Optional[str], fallback: Optional[str] = None) -> Optional[str]:
    if not customer_id:
        return fallback
    try:
        c = await db.customers.find_one({"id": customer_id}, {"_id": 0, "name": 1, "full_name": 1, "email": 1})
        if c:
            return c.get("name") or c.get("full_name") or c.get("email") or fallback
    except Exception:
        pass
    return fallback


@fastapi_app.get("/api/carfax/admin/analytics", dependencies=[Depends(require_manager_or_admin)])
async def carfax_admin_analytics():
    try:
        total = await db.carfax_requests.count_documents({})
        pending = await db.carfax_requests.count_documents({"status": "pending"})
        processing = await db.carfax_requests.count_documents({"status": "processing"})
        uploaded = await db.carfax_requests.count_documents({"status": "uploaded"})
        rejected = await db.carfax_requests.count_documents({"status": "rejected"})
        # cost rollup from uploaded reports
        agg = await db.carfax_requests.aggregate([
            {"$match": {"status": "uploaded"}},
            {"$group": {"_id": None, "spent": {"$sum": {"$ifNull": ["$actualCost", 0]}},
                        "est": {"$sum": {"$ifNull": ["$estimatedCost", 0]}}}},
        ]).to_list(length=1)
        total_cost = round(agg[0]["spent"], 2) if agg else 0
        cost_saved = round(max(0, (agg[0]["est"] - agg[0]["spent"])), 2) if agg else 0
        return {
            "totalRequests": total, "pendingRequests": pending, "processingRequests": processing,
            "uploadedRequests": uploaded, "rejectedRequests": rejected,
            "totalCost": total_cost, "costSaved": cost_saved,
        }
    except Exception:
        return {"totalRequests": 0, "pendingRequests": 0, "processingRequests": 0,
                "uploadedRequests": 0, "rejectedRequests": 0, "totalCost": 0, "costSaved": 0}


@fastapi_app.get("/api/carfax/admin/queue", dependencies=[Depends(require_manager_or_admin)])
async def carfax_admin_queue():
    """Full board (array) so the admin sees pending → processing → uploaded."""
    try:
        rows = await db.carfax_requests.find({}, {"_id": 0}).sort("createdAt", -1).to_list(length=500)
        return rows
    except Exception:
        return []


@fastapi_app.get("/api/carfax/me")
async def carfax_me(current_user: Dict[str, Any] = Depends(require_user)):
    """Array of the current user's Carfax reports (cabinet)."""
    uid = current_user.get("id") or current_user.get("sub")
    cid = current_user.get("customerId") or uid
    ids = [x for x in {uid, cid} if x]
    try:
        rows = await db.carfax_requests.find(
            {"$or": [{"userId": {"$in": ids}}, {"customerId": {"$in": ids}}]},
            {"_id": 0},
        ).sort("createdAt", -1).to_list(length=100)
        return rows
    except Exception:
        return []


@fastapi_app.post("/api/carfax/request")
async def carfax_request(data: Dict[str, Any] = Body(...), current_user: Dict[str, Any] = Depends(require_user)):
    """Customer self-service request → enters the manager queue as 'pending'."""
    vin = (data.get("vin") or "").strip().upper()
    if not vin:
        raise HTTPException(400, "VIN is required")
    uid = current_user.get("id") or current_user.get("sub")
    cid = current_user.get("customerId") or uid
    req = {
        "id": f"cfx_{uuid.uuid4().hex[:12]}",
        "vin": vin,
        "userId": uid,
        "customerId": cid,
        "userName": await _carfax_customer_name(cid, current_user.get("name") or current_user.get("email")),
        "status": "pending",
        "source": "customer",
        "pdfUrl": None,
        "pdfFilename": None,
        "actualCost": None,
        "estimatedCost": data.get("estimatedCost") or 45,
        "createdAt": datetime.now(timezone.utc).isoformat(),
    }
    await db.carfax_requests.insert_one(dict(req))
    return {"success": True, "requestId": req["id"], "status": req["status"], "data": _carfax_clean(req)}


@fastapi_app.patch("/api/carfax/{request_id}/approve", dependencies=[Depends(require_manager_or_admin)])
async def carfax_approve(request_id: str):
    res = await db.carfax_requests.update_one(
        {"id": request_id}, {"$set": {"status": "processing", "approvedAt": datetime.now(timezone.utc).isoformat()}})
    if res.matched_count == 0:
        raise HTTPException(404, "Carfax request not found")
    return {"success": True, "status": "processing"}


@fastapi_app.patch("/api/carfax/{request_id}/reject", dependencies=[Depends(require_manager_or_admin)])
async def carfax_reject(request_id: str, data: Dict[str, Any] = Body(default={})):
    reason = (data or {}).get("reason") if isinstance(data, dict) else None
    res = await db.carfax_requests.update_one(
        {"id": request_id},
        {"$set": {"status": "rejected", "rejectReason": reason, "rejectedAt": datetime.now(timezone.utc).isoformat()}})
    if res.matched_count == 0:
        raise HTTPException(404, "Carfax request not found")
    return {"success": True, "status": "rejected"}


@fastapi_app.post("/api/carfax/{request_id}/upload-pdf", dependencies=[Depends(require_manager_or_admin)])
async def carfax_upload_pdf(request_id: str, data: Dict[str, Any] = Body(...)):
    """Attach the report by URL (manager already hosts the PDF somewhere)."""
    pdf_url = (data.get("pdfUrl") or "").strip()
    if not pdf_url:
        raise HTTPException(400, "pdfUrl is required")
    existing = await db.carfax_requests.find_one({"id": request_id}, {"_id": 0, "vin": 1})
    if not existing:
        raise HTTPException(404, "Carfax request not found")
    await db.carfax_requests.update_one(
        {"id": request_id},
        {"$set": {
            "status": "uploaded", "pdfUrl": pdf_url,
            "pdfFilename": data.get("pdfFilename") or f"carfax-{existing.get('vin','report')}.pdf",
            "actualCost": data.get("actualCost"),
            "uploadedAt": datetime.now(timezone.utc).isoformat(),
        }})
    return {"success": True, "status": "uploaded", "pdfUrl": pdf_url}


@fastapi_app.post("/api/carfax/{request_id}/upload-file", dependencies=[Depends(require_manager_or_admin)])
async def carfax_upload_file(
    request_id: str,
    file: UploadFile = File(...),
    actualCost: Optional[float] = Form(default=None),
):
    """Manager uploads the actual PDF file they obtained externally.
    Stored under /api/static/carfax/{id}.pdf and exposed for cabinet download."""
    existing = await db.carfax_requests.find_one({"id": request_id}, {"_id": 0, "vin": 1})
    if not existing:
        raise HTTPException(404, "Carfax request not found")
    ctype = (file.content_type or "").lower()
    if ctype not in ("application/pdf", "application/octet-stream") and not (file.filename or "").lower().endswith(".pdf"):
        raise HTTPException(400, "Only PDF files are accepted")
    content = await file.read()
    if len(content) > 25 * 1024 * 1024:
        raise HTTPException(413, "PDF too large (max 25MB)")
    try:
        _CARFAX_DIR.mkdir(parents=True, exist_ok=True)
    except Exception:
        pass
    dest = _CARFAX_DIR / f"{request_id}.pdf"
    with open(dest, "wb") as f:
        f.write(content)
    ts = int(datetime.now(timezone.utc).timestamp())
    url = f"/api/static/carfax/{request_id}.pdf?v={ts}"
    await db.carfax_requests.update_one(
        {"id": request_id},
        {"$set": {
            "status": "uploaded", "pdfUrl": url,
            "pdfFilename": file.filename or f"carfax-{existing.get('vin','report')}.pdf",
            "actualCost": actualCost,
            "uploadedAt": datetime.now(timezone.utc).isoformat(),
        }})
    return {"success": True, "status": "uploaded", "pdfUrl": url}


@fastapi_app.post("/api/admin/customers/{customer_id}/carfax", dependencies=[Depends(require_manager_or_admin)])
async def carfax_manager_attach(
    customer_id: str,
    file: Optional[UploadFile] = File(default=None),
    vin: str = Form(...),
    pdfUrl: Optional[str] = Form(default=None),
    actualCost: Optional[float] = Form(default=None),
):
    """Customer 360 action: manager attaches a CarFax report (file or URL)
    directly to a customer. Immediately available in the customer cabinet."""
    vin = (vin or "").strip().upper()
    if not vin:
        raise HTTPException(400, "VIN is required")
    rid = f"cfx_{uuid.uuid4().hex[:12]}"
    pdf_url = (pdfUrl or "").strip() or None
    pdf_filename = f"carfax-{vin}.pdf"
    if file is not None:
        content = await file.read()
        if len(content) > 25 * 1024 * 1024:
            raise HTTPException(413, "PDF too large (max 25MB)")
        if (file.content_type or "").lower() not in ("application/pdf", "application/octet-stream") and not (file.filename or "").lower().endswith(".pdf"):
            raise HTTPException(400, "Only PDF files are accepted")
        try:
            _CARFAX_DIR.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass
        with open(_CARFAX_DIR / f"{rid}.pdf", "wb") as f:
            f.write(content)
        ts = int(datetime.now(timezone.utc).timestamp())
        pdf_url = f"/api/static/carfax/{rid}.pdf?v={ts}"
        pdf_filename = file.filename or pdf_filename
    if not pdf_url:
        raise HTTPException(400, "Provide a PDF file or pdfUrl")
    doc = {
        "id": rid, "vin": vin, "userId": customer_id, "customerId": customer_id,
        "userName": await _carfax_customer_name(customer_id),
        "status": "uploaded", "source": "manager",
        "pdfUrl": pdf_url, "pdfFilename": pdf_filename,
        "actualCost": actualCost, "estimatedCost": actualCost,
        "createdAt": datetime.now(timezone.utc).isoformat(),
        "uploadedAt": datetime.now(timezone.utc).isoformat(),
    }
    await db.carfax_requests.insert_one(dict(doc))
    return {"success": True, "data": _carfax_clean(doc)}


@fastapi_app.delete("/api/carfax/{request_id}", dependencies=[Depends(require_manager_or_admin)])
async def carfax_delete(request_id: str):
    """Remove a Carfax report/request (and its stored PDF, if any)."""
    existing = await db.carfax_requests.find_one({"id": request_id}, {"_id": 0})
    if not existing:
        raise HTTPException(404, "Carfax request not found")
    try:
        f = _CARFAX_DIR / f"{request_id}.pdf"
        if f.exists():
            f.unlink()
    except Exception:
        pass
    await db.carfax_requests.delete_one({"id": request_id})
    return {"success": True}

