@fastapi_app.get("/api/calculator/config/usa-inland-defaults")
async def calculator_get_usa_inland_defaults():
    """Return the bundled USA-inland-model defaults + the live overrides
    from the active profile.

    Response shape::

        {
          "exportPorts":        [...],   # 8 ports
          "destinationPorts":   [...],   # 8 EU ports
          "stateMatrix":        { "TX": {port, miles}, ... },
          "buckets":            [...],   # 5 distance buckets
          "vehicleMultipliers": { "sedan": 1.0, ... },
          "auctionFallback":    { "copart": "FL", ... },
          "profileOverrides":   { ... live overrides if any ... }
        }
    """
    from app.core.usa_inland_model import (
        USA_EXPORT_PORTS,
        USA_DESTINATION_PORTS,
        USA_STATE_TO_PORT,
        STATE_PORT_DISTANCES,
        USA_INLAND_BUCKETS_DEFAULT,
        USA_INLAND_VEHICLE_MULTIPLIERS_DEFAULT,
        AUCTION_DEFAULT_STATE,
    )
    await _ensure_calculator_seed()
    prof = await db.calculator_profile.find_one(
        {"code": DEFAULT_PROFILE_CODE}, {"_id": 0}
    ) or {}
    return {
        "exportPorts":        USA_EXPORT_PORTS,
        "destinationPorts":   USA_DESTINATION_PORTS,
        "stateMatrix":        USA_STATE_TO_PORT,         # preferred port per state
        "stateDistances":     STATE_PORT_DISTANCES,      # 51 × 8 derived miles (read-only)
        "buckets":            USA_INLAND_BUCKETS_DEFAULT,
        "vehicleMultipliers": USA_INLAND_VEHICLE_MULTIPLIERS_DEFAULT,
        "auctionFallback":    AUCTION_DEFAULT_STATE,
        "profileOverrides":   prof.get("usaInlandModel") or {},
        "profileCode":        DEFAULT_PROFILE_CODE,
    }


# ── Wave 4 — Ocean Freight Model (bucket × shared multiplier + dest. adj.) ─
# Same philosophy as the inland model. Static defaults + admin overrides
# live in ``calculator_profile.oceanFreightModel``. Vehicle multipliers
# are NOT duplicated here — the ocean engine reads them from the inland
# model so SUVs/pickups/etc. have a single footprint coefficient.

@fastapi_app.get("/api/calculator/config/ocean-defaults")
async def calculator_get_ocean_defaults():
    """Return bundled ocean-freight defaults + live overrides.

    Wave 4.1 — flat lane matrix model (no buckets, no deltas).

    Response shape::

        {
          "exportPorts":       [...],  # 8 USA ports (shared with inland)
          "destinationPorts":  [...],  # 8 EU ports
          "laneMatrix":        { usa_port: { eu_port: usd, ... }, ... }
          "sharedMultipliers": { sedan: 1.0, ... }  # read-only view
          "profileOverrides":  { ... current admin overrides ... }
        }
    """
    from app.core.usa_inland_model import (
        USA_EXPORT_PORTS,
        USA_DESTINATION_PORTS,
        USA_INLAND_VEHICLE_MULTIPLIERS_DEFAULT,
    )
    from app.core.ocean_freight_model import (
        OCEAN_LANE_MATRIX_DEFAULT,
        DEFAULT_DESTINATION_PORT,
    )
    await _ensure_calculator_seed()
    prof = await db.calculator_profile.find_one(
        {"code": DEFAULT_PROFILE_CODE}, {"_id": 0}
    ) or {}
    inland_overrides = prof.get("usaInlandModel") or {}
    shared_mult = {
        **USA_INLAND_VEHICLE_MULTIPLIERS_DEFAULT,
        **(inland_overrides.get("vehicleMultipliers") or {}),
    }
    ocean_overrides = prof.get("oceanFreightModel") or {}
    return {
        "exportPorts":            USA_EXPORT_PORTS,
        "destinationPorts":       USA_DESTINATION_PORTS,
        "laneMatrix":             OCEAN_LANE_MATRIX_DEFAULT,
        "defaultDestinationPort": DEFAULT_DESTINATION_PORT,
        "sharedMultipliers":      shared_mult,
        "profileOverrides":       ocean_overrides,
        "profileCode":            DEFAULT_PROFILE_CODE,
    }


# ── Wave 4.2 — EU Delivery (port → Sofia BG) matrix defaults ──────────────
# Mirror of the ocean-defaults endpoint. The EU-delivery engine prices the
# trucking leg from each of the 8 EU destination ports to Sofia (Bulgaria,
# fixed final hub) in EUR per vehicle type. Admin can override any cell
# via the EuDeliveryModelEditor card on /admin/calculator. FX rate comes
# from the profile (fxUsdToEur, shared with the Korea calculator) so the
# unified total is always rendered in USD.
@fastapi_app.get("/api/calculator/config/eu-delivery-defaults")
async def calculator_get_eu_delivery_defaults():
    """Return bundled EU-delivery defaults + live overrides.

    Response shape::

        {
          "destinationPorts":   [...],   # 8 EU ports (same as Ocean dst)
          "finalHub":           "sofia_bg",
          "finalHubLabel":      "Sofia (BG)",
          "vehicleTypes":       [{"code","name"}, ...],   # 7 types, ordered
          "matrix":             { eu_port: { vehicle: eur, ... }, ... },
          "fxUsdToEur":         float,   # current FX from profile
          "profileOverrides":   { ... live admin overrides ... },
          "profileCode":        "default",
        }
    """
    from app.core.usa_inland_model import USA_DESTINATION_PORTS
    from app.core.eu_delivery_model import (
        EU_DELIVERY_MATRIX_DEFAULT_EUR,
        EU_DELIVERY_FINAL_HUB,
        EU_DELIVERY_FINAL_HUB_LABEL,
        DEFAULT_EU_PORT,
    )
    from app.core.calculator_constants import KOREA_FX_USD_TO_EUR
    await _ensure_calculator_seed()
    prof = await db.calculator_profile.find_one(
        {"code": DEFAULT_PROFILE_CODE}, {"_id": 0}
    ) or {}
    eu_overrides = prof.get("euDeliveryModel") or {}
    try:
        fx = float(prof.get("fxUsdToEur") or KOREA_FX_USD_TO_EUR)
    except (TypeError, ValueError):
        fx = KOREA_FX_USD_TO_EUR
    return {
        "destinationPorts":   USA_DESTINATION_PORTS,
        "finalHub":           EU_DELIVERY_FINAL_HUB,
        "finalHubLabel":      EU_DELIVERY_FINAL_HUB_LABEL,
        "defaultEuPort":      DEFAULT_EU_PORT,
        "vehicleTypes": [
            {"code": "sedan",      "name": "Sedan"},
            {"code": "suv",        "name": "SUV / Crossover"},
            {"code": "bigSUV",     "name": "Big SUV / 4x4"},
            {"code": "pickup",     "name": "Pickup"},
            {"code": "van",        "name": "Van"},
            {"code": "motorcycle", "name": "Motorcycle"},
            {"code": "trailer",    "name": "Trailer"},
        ],
        "matrix":             EU_DELIVERY_MATRIX_DEFAULT_EUR,
        "fxUsdToEur":         fx,
        "profileOverrides":   eu_overrides,
        "profileCode":        DEFAULT_PROFILE_CODE,
    }


@fastapi_app.get("/api/calculator/admin/stats")
async def calculator_admin_stats():
    """Live counts used by the admin panel.

    Returns both the current keys and the legacy ones used by older UI
    callers (CalculatorAdmin.js expects ``totalQuotes`` / ``totalQuotedValue`` /
    ``profiles`` / ``activeProfile``).
    """
    await _ensure_calculator_seed()
    profile_active = await db.calculator_profile.count_documents({"isActive": True})
    profiles_total = await db.calculator_profile.count_documents({})
    routes_active = await db.calculator_routes.count_documents({"isActive": True})
    rules_active = await db.calculator_auction_fees.count_documents({"isActive": True})
    quotes_total = await db.quotes.count_documents({})
    leads_total = await db.leads.count_documents({"source": "calculator"})

    # Sum of the "total" field across saved quotes (best-effort, ignores
    # malformed docs).
    total_value = 0.0
    try:
        async for q in db.quotes.find({}, {"calculation.total": 1, "_id": 0}):
            try:
                total_value += float((q.get("calculation") or {}).get("total") or 0)
            except (TypeError, ValueError):
                continue
    except Exception:
        pass

    active_profile_doc = await db.calculator_profile.find_one(
        {"isActive": True}, {"_id": 0, "name": 1, "code": 1}
    )
    active_profile_label = (active_profile_doc or {}).get("name") or DEFAULT_PROFILE_CODE

    return {
        # current schema
        "profileActive": profile_active,
        "routesActive": routes_active,
        "auctionRulesActive": rules_active,
        "quotes": quotes_total,
        "leads": leads_total,
        # legacy aliases (older admin UI)
        "totalQuotes": quotes_total,
        "totalQuotedValue": round(total_value, 2),
        "profiles": profiles_total,
        "activeProfile": active_profile_label,
    }

@fastapi_app.post("/api/calculator/quote")
async def calculator_quote(data: Dict[str, Any] = Body(...)):
    """Create a quote (persists full calculator context incl. damaged status)."""
    quote_id = f"quote-{datetime.now(timezone.utc).timestamp()}"
    quote = {
        "id": quote_id,
        "vin": data.get("vin"),
        "price": data.get("price"),
        "invoicePrice": data.get("invoicePrice"),
        "origin": (data.get("origin") or "usa").lower(),
        "vehicleType": data.get("vehicleType"),
        "damaged": bool(data.get("damaged") or False),
        "port": data.get("port") or ("constanta" if (data.get("origin") or "").lower() == "korea" else "burgas"),
        "auction": data.get("auction"),
        "useLogisticsPackage": data.get("useLogisticsPackage"),
        "additionalFees": data.get("additionalFees"),
        "scenario": data.get("scenario", "standard"),
        "source": data.get("source", "calculator"),
        "calculation": data.get("calculation"),
        "contact": data.get("contact"),
        "created_at": datetime.now(timezone.utc).isoformat(),
    }
    await db.quotes.insert_one(quote)
    # Remove _id before returning to avoid serialization issues
    quote.pop("_id", None)
    return {"success": True, "quote": quote}

@fastapi_app.patch("/api/calculator/quote/{quote_id}/scenario")
async def update_quote_scenario(quote_id: str, data: Dict[str, Any] = Body(...)):
    """Update quote scenario"""
    await db.quotes.update_one(
        {"id": quote_id},
        {"$set": {"scenario": data.get("scenario")}}
    )
    return {"success": True}


