# ═══════════════════════════════════════════════════════════════════
# INGESTION/PARSER ADMIN ENDPOINTS
# ═══════════════════════════════════════════════════════════════════
def _derive_parser_status(key: str, p) -> str:
    """P1.4 — Honest 4-state parser lifecycle for the admin UI.

    Returns one of: ``working`` / ``needs_config`` / ``disabled`` / ``failing``.

    Maps the legacy ``{enabled, status, readiness, errors_count, items_parsed}``
    tuple to a single operator-friendly state so the admin UI can render a
    correct badge without re-implementing the rules on the frontend.
    """
    readiness = (getattr(p, "readiness", "") or "").lower()
    if readiness in ("broken", "incomplete"):
        return "disabled"
    if readiness == "needs_config":
        return "needs_config"
    errors = int(getattr(p, "errors_count", 0) or 0)
    items = int(getattr(p, "items_parsed", 0) or 0)
    if errors > 0 and items == 0:
        return "failing"
    if getattr(p, "enabled", False) and (getattr(p, "status", "") in ("active", "live-only")):
        return "working"
    return "disabled"



@fastapi_app.get("/api/ingestion/admin/parsers", dependencies=[Depends(require_admin)])
async def ingestion_parsers():
    """Unified parser registry with real status for each source"""
    stats = aggregator.get_stats()
    v3_stats = session_service.get_stats()
    
    result = []
    for key, p in PARSER_REGISTRY.items():
        entry = {
            "source": p.source,
            "name": p.name,
            "type": p.type,
            "status": p.status,
            "enabled": p.enabled,
            "readiness": p.readiness,
            "readinessDetail": p.readiness_detail,
            "lastRunAt": p.last_run,
            "lastSuccessAt": p.last_run if p.items_parsed > 0 else None,
            "itemsParsed": p.items_parsed,
            "itemsCreated": p.items_parsed,
            "errorsCount": p.errors_count,
            "isPaused": not p.enabled,
            "circuitState": "closed",
            "endpoints": p.endpoints,
            # ── P1.1 — Honest "needs auth" indicator ────────────────────
            # bitmotors / westmotors / lemon use public sitemaps + plain
            # HTTPS — no API key needed. Showing "API key missing" on these
            # was misleading. We now set apiKeyConfigured=None (= "n/a")
            # for sources that explicitly don't need auth.
            "apiKeyConfigured": (
                None
                if key in ("bitmotors", "westmotors", "lemon") or p.type != "api"
                else bool(p.api_key)
            ),
            # ── P1.4 — Honest 4-state parser status ─────────────────────
            # Replaces the {active|standby} boolean with a real lifecycle.
            "parserStatus": _derive_parser_status(key, p),
        }
        
        # Enrich with live data
        if key == "bitmotors" and bitmotors_parser_instance:
            scraper_stats = bitmotors_parser_instance.get_stats()
            entry["status"] = "active" if scraper_stats.get("running") else "standby"
            entry["enabled"] = scraper_stats.get("running", False)
            entry["itemsParsed"] = scraper_stats.get("total_scraped", 0)
            entry["itemsCreated"] = scraper_stats.get("total_new", 0)
            entry["errorsCount"] = scraper_stats.get("total_errors", 0)
            entry["lastRunAt"] = scraper_stats.get("last_run")
            entry["lastSuccessAt"] = scraper_stats.get("last_success")
            entry["scraperStats"] = scraper_stats
            try:
                db_count = await db.vin_data.count_documents({"source": "bitmotors"})
                entry["documentsInDB"] = db_count
            except Exception:
                pass
        elif key == "carfast":
            entry["extensionSessions"] = v3_stats.get("active_sessions", 0)
            entry["itemsParsed"] = stats.get("total_vins", 0)
            if stats.get("total_vins", 0) > 0:
                entry["status"] = "active"
        elif key == "bidcars":
            try:
                count = await db.bidcars_vehicles.count_documents({})
                entry["itemsParsed"] = count
            except Exception:
                pass
        elif key == "autoastat":
            try:
                count = await db.autoastat_vehicles.count_documents({})
                entry["itemsParsed"] = count
            except Exception:
                pass
        elif key == "westmotors":
            try:
                count = await db.vin_data_westmotors.count_documents({})
                entry["documentsInDB"] = count
                entry["itemsParsed"] = count
            except Exception:
                pass
            if westmotors_sync_instance and hasattr(westmotors_sync_instance, "settings"):
                entry["status"] = "active"
                entry["enabled"] = True
                entry["intervalSeconds"] = westmotors_sync_instance.settings.get("incremental_interval_sec", 3600)
        elif key == "lemon":
            try:
                count = await db.vin_data_lemon.count_documents({})
                entry["documentsInDB"] = count
                entry["itemsParsed"] = count
            except Exception:
                pass
            if lemon_sync_instance and hasattr(lemon_sync_instance, "settings"):
                entry["status"] = "active"
                entry["enabled"] = True
                entry["intervalSeconds"] = lemon_sync_instance.settings.get("discovery_incremental_interval_sec", 3600)
        elif key == "carfast":
            try:
                count = await db.carfast_vehicles.count_documents({})
                entry["itemsParsed"] = count
            except Exception:
                pass
        elif key in ("poctra", "carsfromwest", "autoauctionhistory", "salvagebid"):
            # Extension-served CF sources: reactive per-VIN lookups (no bulk
            # catalogue). Surface real lookup stats + honest uplink status.
            try:
                _h = _ms_health() or {}
                _src = (_h.get("sources") or {}).get(key) or {}
                entry["itemsParsed"] = int(_src.get("hits") or 0)
                entry["errorsCount"] = int(_src.get("errors") or 0)
                entry["documentsInDB"] = int(_src.get("hits") or 0)
            except Exception:
                pass
            try:
                _online = sum(1 for c in _ms_get_clients() if c.get("online"))
            except Exception:
                _online = 0
            entry["extensionSessions"] = _online
            if _online > 0:
                entry["status"] = "active"
                entry["enabled"] = True
                entry["readiness"] = "ready"
                entry["readinessDetail"] = (
                    f"Chrome Extension online ({_online}) — this source is served "
                    "on demand when managers look up a VIN."
                )
            else:
                entry["status"] = "standby"
                entry["readiness"] = "needs_config"

        result.append(entry)
    
    return {"success": True, "parsers": result}

@fastapi_app.get("/api/ingestion/admin/parsers/audit", dependencies=[Depends(require_admin)])
async def parsers_audit():
    """Full audit report of all parser integrations"""
    audit = []
    for key, p in PARSER_REGISTRY.items():
        # Count data in DB
        collection_map = {
            "bidcars": "bidcars_vehicles",
            "autoastat": "autoastat_vehicles",
            "bitmotors": "vin_data",
            "westmotors": "vin_data_westmotors",
            "lemon": "vin_data_lemon",
        }
        db_count = 0
        try:
            coll = collection_map.get(key, "vin_data")
            db_count = await db[coll].count_documents({})
        except Exception:
            pass
        
        audit.append({
            "source": p.source,
            "name": p.name,
            "type": p.type,
            "status": p.status,
            "readiness": p.readiness,
            "readinessDetail": p.readiness_detail,
            "enabled": p.enabled,
            "dbCollection": collection_map.get(key, "N/A"),
            "documentsInDB": db_count,
            "hasIngestEndpoint": any("/ingest" in e for e in p.endpoints),
            "hasSearchEndpoint": any("/search" in e or "/vehicles" in e for e in p.endpoints),
            "hasParseEndpoint": any("/parse" in e for e in p.endpoints),
            "endpoints": p.endpoints,
        })
    
    return {
        "success": True,
        "generatedAt": datetime.now(timezone.utc).isoformat(),
        "totalParsers": len(PARSER_REGISTRY),
        "activeParsers": sum(1 for p in PARSER_REGISTRY.values() if p.status == "active"),
        "standbyParsers": sum(1 for p in PARSER_REGISTRY.values() if p.status == "standby"),
        "audit": audit,
    }

