@fastapi_app.post("/api/ingestion/admin/parsers/{source}/run", dependencies=[Depends(require_master_admin)])
async def run_parser(source: str):
    """Start parser"""
    p = PARSER_REGISTRY.get(source)
    if not p:
        return {"success": False, "message": f"Unknown parser: {source}"}
    if p.readiness == "broken":
        return {"success": False, "message": f"{p.name}: {p.readiness_detail}"}
    if p.readiness == "incomplete":
        return {"success": False, "message": f"{p.name} is incomplete: {p.readiness_detail}"}
    
    p.enabled = True
    p.status = "active"
    p.last_run = datetime.now(timezone.utc).isoformat()
    
    if source == "carfast":
        parser_config.enabled = True
    elif source == "bitmotors" and bitmotors_parser_instance:
        result = bitmotors_parser_instance.start()
        return {"success": True, "message": f"{p.name} parser started", "status": p.status, "scraper": result}
    elif source == "westmotors" and westmotors_sync_instance:
        westmotors_sync_instance.start()
        return {"success": True, "message": f"{p.name} sync started", "status": p.status}
    elif source == "lemon" and lemon_sync_instance:
        lemon_sync_instance.start()
        return {"success": True, "message": f"{p.name} sync started", "status": p.status}
    elif source in ("bidcars", "autoastat") or (p and p.type in ("extension", "passive")):
        # Served by the Chrome Extension — "start" arms the source and reports
        # extension connectivity instead of pretending a server worker booted.
        try:
            clients = _ms_get_clients()
        except Exception:
            clients = []
        online = [c for c in clients if c.get("online")]
        if not online:
            p.status = "standby"
            return {
                "success": False,
                "needsExtension": True,
                "status": "standby",
                "extensionsOnline": 0,
                "message": (
                    f"{p.name}: armed, but no Chrome Extension is online. Install the "
                    f"extension + paste the CRM access key (HMAC) to start receiving data."
                ),
            }
        return {
            "success": True,
            "status": "active",
            "extensionsOnline": len(online),
            "message": f"{p.name} armed — {len(online)} extension(s) online.",
        }
    
    return {"success": True, "message": f"{p.name} parser started", "status": p.status}

@fastapi_app.post("/api/ingestion/admin/parsers/{source}/stop", dependencies=[Depends(require_master_admin)])
async def stop_parser(source: str):
    """Stop parser"""
    p = PARSER_REGISTRY.get(source)
    if not p:
        return {"success": False, "message": f"Unknown parser: {source}"}
    
    p.enabled = False
    p.status = "standby"
    
    if source == "carfast":
        parser_config.enabled = False
    elif source == "bitmotors" and bitmotors_parser_instance:
        result = bitmotors_parser_instance.stop()
        return {"success": True, "message": f"{p.name} parser stopped", "status": p.status, "scraper": result}
    elif source == "westmotors" and westmotors_sync_instance:
        westmotors_sync_instance.stop()
        return {"success": True, "message": f"{p.name} sync stopped", "status": p.status}
    elif source == "lemon" and lemon_sync_instance:
        lemon_sync_instance.stop()
        return {"success": True, "message": f"{p.name} sync stopped", "status": p.status}
    
    return {"success": True, "message": f"{p.name} parser stopped", "status": p.status}

@fastapi_app.post("/api/ingestion/admin/parsers/{source}/run-once", dependencies=[Depends(require_master_admin)])
async def run_once_parser(source: str, data: Dict[str, Any] = Body(default={})):
    """Trigger a single immediate run-once cycle for the parser.

    Accepts optional limits in the request body:
      - ``max_pages`` (int)     — cap on pages to fetch (bitmotors ~30 cars/page).
      - ``max_vehicles`` (int)  — soft cap on cars to upsert.

    Returns the scraper's run-once stats (items_parsed, items_created, errors, …).
    """
    p = PARSER_REGISTRY.get(source)
    if not p:
        return {"success": False, "message": f"Unknown parser: {source}"}
    if p.readiness in ("broken", "incomplete"):
        return {"success": False, "message": f"{p.name} not runnable: {p.readiness_detail}"}

    max_pages = int(data.get("max_pages") or 0)
    max_vehicles = int(data.get("max_vehicles") or 0)
    # Convenience: derive pages from a per-vehicle cap (≈30 cars/page on bitmotors)
    if max_vehicles and not max_pages:
        max_pages = max(1, (max_vehicles // 30) + 1)

    try:
        if source == "bitmotors":
            target = bitmotors_full_sync_instance or bitmotors_incremental_instance
            if not target:
                # Lazy-init a BitmotorsFullSync on first manual run if startup
                # didn't seed one (cold-start path uses a local instance).
                try:
                    import bitmotors_scraper as _bms
                    target = _bms.BitmotorsFullSync(db)
                    await target.load_settings()
                    target.running = True
                    globals()["bitmotors_full_sync_instance"] = target
                    logger.info("[parsers/run-once] lazy-init BitmotorsFullSync")
                except Exception as ie:
                    return {"success": False, "message": f"BidMotors sync init failed: {ie}"}
            if max_pages and hasattr(target, "settings"):
                target.settings["max_pages"] = max_pages
            result = await target.run_once()
            return {"success": True, "message": f"{p.name} run-once finished", "result": result, "max_pages": max_pages}
        elif source == "bitmotors_incremental" or (source == "bitmotors" and not bitmotors_full_sync_instance):
            if not bitmotors_incremental_instance:
                return {"success": False, "message": "BidMotors incremental not initialised"}
            result = await bitmotors_incremental_instance.run_once(pages=max_pages or None)
            return {"success": True, "message": f"{p.name} incremental run-once finished", "result": result}
        elif source == "westmotors":
            if not westmotors_sync_instance:
                return {"success": False, "message": "WestMotors sync not initialised"}
            # Hourly incremental is much cheaper than full daily; default to incremental
            result = await westmotors_sync_instance.run_incremental_sync()
            return {"success": True, "message": f"{p.name} run-once finished", "result": result}
        elif source == "lemon":
            if not lemon_sync_instance:
                return {"success": False, "message": "Lemon sync not initialised"}
            # LemonSync exposes `run_incremental_discovery` (sitemap sweep),
            # not `run_incremental_sync` — keep the dispatch robust against
            # both naming conventions.
            if hasattr(lemon_sync_instance, "run_incremental_discovery"):
                result = await lemon_sync_instance.run_incremental_discovery()
            elif hasattr(lemon_sync_instance, "run_incremental_sync"):
                result = await lemon_sync_instance.run_incremental_sync()
            elif hasattr(lemon_sync_instance, "run_once"):
                result = await lemon_sync_instance.run_once()
            else:
                return {"success": False, "message": "Lemon sync has no run-once method"}
            return {"success": True, "message": f"{p.name} run-once finished", "result": result}
        elif source in ("bidcars", "autoastat") or (p and p.type in ("extension", "passive")):
            # CF-protected sources are served by the Chrome Extension, not the
            # server. "Run" here = confirm a client is online to deliver data.
            try:
                clients = _ms_get_clients()
            except Exception:
                clients = []
            online = [c for c in clients if c.get("online")]
            p.enabled = True
            p.status = "active"
            if not online:
                return {
                    "success": False,
                    "needsExtension": True,
                    "message": (
                        f"{p.name}: no Chrome Extension online. Install the extension, "
                        f"set Backend URL + CRM access key (HMAC), then it will deliver data."
                    ),
                    "extensionsOnline": 0,
                }
            return {
                "success": True,
                "message": f"{p.name} armed — {len(online)} extension(s) online delivering data.",
                "extensionsOnline": len(online),
            }
        return {"success": False, "message": f"run-once not implemented for {source}"}
    except Exception as e:
        logger.exception(f"[parsers/run-once] {source} failed: {e}")
        return {"success": False, "message": f"{p.name} run-once failed: {e}"}

# ═══════════════════════════════════════════════════════════════════
# ENGINE SELF-HEAL — install the heavy Playwright stack on admin command
# ───────────────────────────────────────────────────────────────────
# Lets an admin "deploy" the bid.cars Playwright engine (playwright +
# playwright_stealth + chromium browser) straight from the panel, without
# a code redeploy. Useful when a fresh prod image shipped without the
# browser binaries ("Missing playwright_stealth module").
#
# NOTE (honest): even with the engine installed, bid.cars stays behind
# Cloudflare — server-side Playwright will hit CF challenges. The reliable
# data path for bid.cars / CF sites is the Chrome Extension. This button
# only clears the "engine missing" state; it does not bypass Cloudflare.
# ═══════════════════════════════════════════════════════════════════
_engine_install_state: Dict[str, Any] = {
    "status": "idle",          # idle | running | success | error
    "source": None,
    "log": [],
    "started_at": None,
    "finished_at": None,
    "message": "",
}


def _engine_probe(deep: bool = False) -> Dict[str, Any]:
    """Check whether the Playwright engine is usable.

    By default this is LIGHTWEIGHT (import checks only) so it is safe to call
    on every status poll. Launching a real Chromium is expensive and, on a
    constrained pod, repeatedly doing so starves the thread-pool and times out
    other endpoints — so the browser launch test only runs when deep=True.
    """
    out = {"playwright": False, "playwright_stealth": False, "chromium": False}
    try:
        import playwright  # noqa: F401
        out["playwright"] = True
    except Exception:
        pass
    try:
        import playwright_stealth  # noqa: F401
        out["playwright_stealth"] = True
    except Exception:
        pass
    if deep and out["playwright"]:
        try:
            from playwright.sync_api import sync_playwright
            with sync_playwright() as _p:
                _b = _p.chromium.launch(headless=True)
                _b.close()
            out["chromium"] = True
        except Exception:
            out["chromium"] = False
    else:
        # Cheap heuristic: chromium browser binary present in the cache dir.
        try:
            import glob as _glob
            import os as _os
            cache = _os.path.expanduser("~/.cache/ms-playwright")
            out["chromium"] = bool(_glob.glob(_os.path.join(cache, "chromium-*")))
        except Exception:
            out["chromium"] = False
    out["ready"] = bool(out["playwright"] and out["playwright_stealth"] and out["chromium"])
    return out


async def _run_engine_install(source: str) -> None:
    """Background task: pip install playwright stack + chromium browser."""
    import sys as _sys
    st = _engine_install_state
    st.update({"status": "running", "source": source, "log": [],
               "started_at": datetime.now(timezone.utc).isoformat(),
               "finished_at": None, "message": "Installing engine…"})

    async def _exec(cmd: List[str], label: str) -> int:
        st["log"].append(f"$ {label}")
        try:
            proc = await asyncio.create_subprocess_exec(
                *cmd,
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.STDOUT,
            )
            assert proc.stdout is not None
            async for raw in proc.stdout:
                line = raw.decode(errors="replace").rstrip()
                if line:
                    st["log"].append(line)
                    if len(st["log"]) > 400:
                        del st["log"][:200]  # keep tail bounded
            return await proc.wait()
        except Exception as e:  # pragma: no cover - defensive
            st["log"].append(f"[exec error] {e}")
            return 1

    try:
        rc1 = await _exec(
            [_sys.executable, "-m", "pip", "install", "--no-input",
             "playwright==1.58.0", "playwright-stealth==2.0.3"],
            "pip install playwright playwright-stealth",
        )
        rc2 = await _exec(
            [_sys.executable, "-m", "playwright", "install", "chromium"],
            "playwright install chromium",
        )
        # System libs (best-effort; often needs root — non-fatal if it fails)
        await _exec(
            [_sys.executable, "-m", "playwright", "install-deps", "chromium"],
            "playwright install-deps chromium (best-effort)",
        )

        probe = await asyncio.get_event_loop().run_in_executor(None, _engine_probe, True)
        st["probe"] = probe
        if probe.get("ready"):
            # Flip runtime availability + readiness so the card stops saying "missing".
            try:
                import importlib
                import bidcars_parser as _bcp
                importlib.reload(_bcp)
                globals()["BIDCARS_AVAILABLE"] = True
                p = PARSER_REGISTRY.get("bidcars")
                if p:
                    p.readiness = "needs_config"
                    p.readiness_detail = (
                        "Engine installed. bid.cars is still Cloudflare-protected — "
                        "use the Chrome Extension for reliable data; server-side "
                        "Playwright may hit CF challenges."
                    )
            except Exception as e:
                st["log"].append(f"[reload warn] {e}")
            st.update({"status": "success",
                       "message": "Engine installed and verified.",
                       "finished_at": datetime.now(timezone.utc).isoformat()})
        else:
            st.update({"status": "error",
                       "message": f"Install finished but engine still not ready (rc1={rc1}, rc2={rc2}).",
                       "finished_at": datetime.now(timezone.utc).isoformat()})
    except Exception as e:
        logger.exception(f"[engine-install] {source} failed: {e}")
        st.update({"status": "error", "message": f"Install failed: {e}",
                   "finished_at": datetime.now(timezone.utc).isoformat()})


@fastapi_app.get("/api/ingestion/admin/parsers/{source}/engine-status",
                 dependencies=[Depends(require_admin)])
async def parser_engine_status(source: str):
    """Report whether the heavy parser engine is installed + any install job."""
    probe = await asyncio.get_event_loop().run_in_executor(None, _engine_probe)
    st = _engine_install_state
    return {
        "success": True,
        "source": source,
        "needsEngine": source == "bidcars",
        "engine": probe,
        "install": {
            "status": st.get("status"),
            "source": st.get("source"),
            "message": st.get("message"),
            "startedAt": st.get("started_at"),
            "finishedAt": st.get("finished_at"),
            "log": st.get("log", [])[-60:],
        },
    }


@fastapi_app.post("/api/ingestion/admin/parsers/{source}/install-engine",
                  dependencies=[Depends(require_master_admin)])
async def parser_install_engine(source: str):
    """Install/deploy the Playwright engine for a parser on admin command."""
    if source != "bidcars":
        return {"success": False, "message": f"{source}: no installable engine (uses public HTTP/sitemap or the Chrome Extension)."}
    if _engine_install_state.get("status") == "running":
        return {"success": False, "message": "Engine install already running.", "status": "running"}
    # Fire-and-forget background task; UI polls engine-status.
    asyncio.create_task(_run_engine_install(source))
    return {"success": True, "message": "Engine install started. Poll engine-status for progress.", "status": "running"}



@fastapi_app.post("/api/ingestion/admin/parsers/{source}/configure", dependencies=[Depends(require_master_admin)])
async def configure_parser(source: str, data: Dict[str, Any] = Body(...)):
    """Configure parser API keys and settings.

    For ``bitmotors`` source, delegates to the BidMotors-specific configure
    handler which also persists to ``parser_settings`` collection.
    Accepted generic keys (other sources): ``max_pages``, ``interval_seconds``,
    ``api_key``.
    """
    p = PARSER_REGISTRY.get(source)
    if not p:
        return {"success": False, "message": f"Unknown parser: {source}"}

    # Delegate to dedicated bitmotors handler (persists interval/max_pages/autostart)
    if source == "bitmotors":
        return await bitmotors_configure_deprecated(data)

    if "api_key" in data:
        p.api_key = data["api_key"]

    # Apply runtime limits to live sync instances
    if source == "westmotors" and westmotors_sync_instance and hasattr(westmotors_sync_instance, "settings"):
        if "incremental_interval_sec" in data:
            westmotors_sync_instance.settings["incremental_interval_sec"] = max(60, int(data["incremental_interval_sec"]))
    elif source == "lemon" and lemon_sync_instance and hasattr(lemon_sync_instance, "settings"):
        if "discovery_incremental_interval_sec" in data:
            lemon_sync_instance.settings["discovery_incremental_interval_sec"] = max(60, int(data["discovery_incremental_interval_sec"]))

    return {"success": True, "message": f"{p.name} configured"}

