@fastapi_app.post("/api/ingestion/admin/promotion/run-once", dependencies=[Depends(require_master_admin)])
async def promote_run_once(data: Dict[str, Any] = Body(default={})):
    """P2 — Manually trigger a promotion sweep.

    Body (all optional):
      - ``sources`` (list[str]) — subset of {"lemon","westmotors"}; default both.
      - ``max_per_source`` (int) — cap per source (default 2000).
      - ``batch`` (int)         — internal page size (default 500).
      - ``only_quality`` (list) — restrict to {"full"} or {"full","partial"}.
    Returns aggregated counters per source.
    """
    if not PROMOTION_AVAILABLE:
        return {"success": False, "message": "catalog_promotion_worker module not loaded"}
    sources = data.get("sources") or ["lemon", "westmotors"]
    max_per_source = int(data.get("max_per_source") or 2000)
    batch = int(data.get("batch") or 500)
    only_quality = data.get("only_quality")  # may be None → both full+partial
    try:
        result = await _promote_all(
            db,
            sources=list(sources),
            max_per_source=max_per_source,
            batch=batch,
            only_quality=list(only_quality) if only_quality else None,
        )
        return {"success": True, "message": "promotion sweep finished", "result": result}
    except Exception as e:
        logger.exception(f"[promote/run-once] failed: {e}")
        return {"success": False, "message": f"promotion failed: {e}"}


@fastapi_app.get("/api/ingestion/admin/promotion/stats", dependencies=[Depends(require_admin)])
async def promote_stats():
    """P2 — Read promotion-worker telemetry."""
    if not PROMOTION_AVAILABLE or not promotion_worker_instance:
        return {"success": False, "message": "promotion worker not initialised", "stats": {}}
    stats = promotion_worker_instance.get_stats()
    # Also surface catalog totals for quick UI badge
    try:
        full = await db.vin_data.count_documents({"data_quality": "full"})
        partial = await db.vin_data.count_documents({"data_quality": "partial"})
        catalog_ready = await db.vin_data.count_documents({"catalog_ready": True})
        total_vin_data = await db.vin_data.count_documents({})
        stats["catalog_totals"] = {
            "total_vin_data": total_vin_data,
            "catalog_ready": catalog_ready,
            "data_quality_full": full,
            "data_quality_partial": partial,
        }
    except Exception:
        pass
    return {"success": True, "stats": stats}


# ═════════════════════════════════════════════════════════════════
# WestMotors lazy parser worker (Phase IV-3)
# ═════════════════════════════════════════════════════════════════
@fastapi_app.get("/api/ingestion/admin/parsers/westmotors/parser-stats",
                 dependencies=[Depends(require_admin)])
async def westmotors_parser_stats():
    """Telemetry for the lazy JSON-LD parser worker."""
    if not WESTMOTORS_PARSER_AVAILABLE or not westmotors_parser_instance:
        return {"success": False, "message": "westmotors parser worker not initialised", "stats": {}}
    return {"success": True, "stats": await westmotors_parser_instance.get_stats()}


@fastapi_app.post("/api/ingestion/admin/parsers/westmotors/parse-now",
                  dependencies=[Depends(require_master_admin)])
async def westmotors_parser_run_once(data: Dict[str, Any] = Body(default={})):
    """Manually fire one batch of the lazy JSON-LD parser worker.

    Body (all optional):
      - ``batch_size`` (int)   — number of rows in this batch.
      - ``concurrency`` (int)  — HTTP concurrency for this batch.
      - ``cycles`` (int)       — how many batches to chain back-to-back.
    """
    if not WESTMOTORS_PARSER_AVAILABLE or not westmotors_parser_instance:
        return {"success": False, "message": "westmotors parser worker not initialised"}

    if data.get("batch_size"):
        await westmotors_parser_instance.configure(batch_size=int(data["batch_size"]))
    if data.get("concurrency"):
        await westmotors_parser_instance.configure(concurrency=int(data["concurrency"]))
    cycles = max(1, int(data.get("cycles") or 1))

    agg = {"picked": 0, "ok": 0, "failed": 0, "no_payload": 0, "skipped": 0, "cycles_run": 0}
    for _ in range(cycles):
        res = await westmotors_parser_instance.run_once()
        if res.get("status") == "busy":
            return {"success": False, "message": "parser is already running", "result": agg}
        for k in ("picked", "ok", "failed", "no_payload", "skipped"):
            agg[k] += int(res.get(k, 0) or 0)
        agg["cycles_run"] += 1
        if res.get("status") == "idle" or res.get("picked", 0) == 0:
            break

    return {"success": True, "result": agg}


@fastapi_app.post("/api/ingestion/admin/parsers/westmotors/parser-configure",
                  dependencies=[Depends(require_master_admin)])
async def westmotors_parser_configure(data: Dict[str, Any] = Body(default={})):
    if not WESTMOTORS_PARSER_AVAILABLE or not westmotors_parser_instance:
        return {"success": False, "message": "westmotors parser worker not initialised"}
    allowed = {"enabled", "concurrency", "delay_per_request_sec", "batch_size",
               "idle_sleep_sec", "max_failures", "stale_after_hours",
               "fetch_timeout_sec", "startup_delay_sec"}
    patch = {k: v for k, v in (data or {}).items() if k in allowed}
    settings = await westmotors_parser_instance.configure(**patch)
    return {"success": True, "settings": settings}


