# ═════════════════════════════════════════════════════════════════
# Compact promotion / parsing dashboard payload (Phase IV-3 UI)
# ═════════════════════════════════════════════════════════════════
@fastapi_app.get("/api/ingestion/admin/promotion/dashboard",
                 dependencies=[Depends(require_admin)])
async def promotion_dashboard():
    """One-shot payload for the admin Promotion Stats UI.

    Returns:
      - ``catalog_totals`` — vin_data classification + catalog_ready
      - ``sources`` — per-source raw collection size + parsed/unparsed/blacklisted
      - ``recent_runs`` — last 10 promotion_runs (collapsed counters)
      - ``promotion_rate`` — rough promoted/hour from last 60 min of runs
      - ``parser_workers`` — westmotors+lemon parser worker stats (best-effort)
    """
    out: Dict[str, Any] = {
        "ts": datetime.now(timezone.utc).isoformat(),
        "catalog_totals": {},
        "sources": [],
        "recent_runs": [],
        "promotion_rate": {"window_minutes": 60, "promoted": 0, "per_hour": 0.0},
        "parser_workers": {},
        "promotion_worker": {},
    }

    # Catalog totals
    try:
        full = await db.vin_data.count_documents({"data_quality": "full"})
        partial = await db.vin_data.count_documents({"data_quality": "partial"})
        shell = await db.vin_data.count_documents({"data_quality": "shell"})
        catalog_ready = await db.vin_data.count_documents({"catalog_ready": True})
        total_vin_data = await db.vin_data.count_documents({})
        legacy = total_vin_data - (full + partial + shell)
        by_source_agg = await db.vin_data.aggregate(
            [{"$group": {"_id": "$source", "n": {"$sum": 1}}}]
        ).to_list(length=50)
        out["catalog_totals"] = {
            "total_vin_data": total_vin_data,
            "catalog_ready": catalog_ready,
            "data_quality_full": full,
            "data_quality_partial": partial,
            "data_quality_shell": shell,
            "legacy_unclassified": max(legacy, 0),
            "by_source": {(x.get("_id") or "unknown"): x.get("n", 0) for x in by_source_agg},
        }
    except Exception as _e:
        logger.debug(f"[promotion_dashboard] catalog totals err: {_e}")

    # Per-source raw collection stats
    for src in ("lemon", "westmotors", "bitmotors"):
        coll = f"vin_data_{src}"
        block: Dict[str, Any] = {"source": src}
        try:
            if coll not in await db.list_collection_names():
                block["present"] = False
                out["sources"].append(block)
                continue
            block["present"] = True
            block["total"] = await db[coll].count_documents({})
            block["active"] = await db[coll].count_documents({"archived": {"$ne": True}})
            block["archived"] = block["total"] - block["active"]
            block["parsed"] = await db[coll].count_documents(
                {"archived": {"$ne": True},
                 "parsed_data": {"$ne": None, "$exists": True}}
            )
            block["unparsed"] = await db[coll].count_documents(
                {"archived": {"$ne": True},
                 "parsed_data": {"$in": [None, {}]}}
            )
            block["blacklisted"] = await db[coll].count_documents(
                {"parse_failed_count": {"$gte": 3}}
            )
            block["parsed_pct"] = round(
                block["parsed"] / block["active"] * 100, 1
            ) if block["active"] else 0.0
        except Exception as _e:
            block["error"] = str(_e)
        out["sources"].append(block)

    # Recent promotion runs (last 10)
    try:
        cursor = (db.promotion_runs
                  .find({})
                  .sort([("started_at", -1)])
                  .limit(10))
        runs = await cursor.to_list(length=10)
        recent: List[Dict[str, Any]] = []
        for r in runs:
            r["_id"] = str(r.get("_id", ""))
            for k in ("started_at", "finished_at"):
                v = r.get(k)
                if hasattr(v, "isoformat"):
                    r[k] = v.isoformat()
            collapsed = {
                "started_at": r.get("started_at"),
                "finished_at": r.get("finished_at"),
                "sources": r.get("sources") or [],
                "results": r.get("results") or [],
            }
            # Build per-source short totals
            tot = {"seen": 0, "promoted_full": 0, "promoted_partial": 0,
                   "shell": 0, "duplicates": 0, "errors": 0}
            for s in r.get("results") or []:
                for k in tot:
                    tot[k] += int(s.get(k) or 0)
            collapsed["totals"] = tot
            recent.append(collapsed)
        out["recent_runs"] = recent
    except Exception as _e:
        logger.debug(f"[promotion_dashboard] recent runs err: {_e}")

    # Approximate promotion rate over last 60 min
    try:
        cutoff = datetime.now(timezone.utc) - timedelta(minutes=60)
        agg_cursor = db.promotion_runs.find({"started_at": {"$gte": cutoff}})
        promoted_total = 0
        async for r in agg_cursor:
            for s in r.get("results") or []:
                promoted_total += int(s.get("promoted_full") or 0)
                promoted_total += int(s.get("promoted_partial") or 0)
        out["promotion_rate"] = {
            "window_minutes": 60,
            "promoted": promoted_total,
            "per_hour": float(promoted_total),
        }
    except Exception as _e:
        logger.debug(f"[promotion_dashboard] rate err: {_e}")

    # Parser worker telemetry
    try:
        if WESTMOTORS_PARSER_AVAILABLE and westmotors_parser_instance:
            out["parser_workers"]["westmotors"] = await westmotors_parser_instance.get_stats()
    except Exception as _e:
        logger.debug(f"[promotion_dashboard] wm parser stats err: {_e}")
    try:
        if LEMON_AVAILABLE and lemon_sync_instance:
            out["parser_workers"]["lemon"] = await lemon_sync_instance.get_stats()
    except Exception as _e:
        logger.debug(f"[promotion_dashboard] lemon stats err: {_e}")

    # Promotion worker
    try:
        if PROMOTION_AVAILABLE and promotion_worker_instance:
            out["promotion_worker"] = promotion_worker_instance.get_stats()
    except Exception as _e:
        logger.debug(f"[promotion_dashboard] promotion worker err: {_e}")

    return {"success": True, "data": out}


# ═════════════════════════════════════════════════════════════════
# Stabilization snapshot (Phase IV-3) — quick ops dashboard
# ═════════════════════════════════════════════════════════════════
@fastapi_app.get("/api/ingestion/admin/stabilization/snapshot",
                 dependencies=[Depends(require_admin)])
async def stabilization_snapshot(window_minutes: int = 5):
    """Compact ops snapshot — memory, Mongo growth, latency, duplicates,
    parser timeouts/bans — taken across a short window.

    Cheap to call repeatedly; intended for an admin auto-refresh tile.
    """
    window_minutes = max(1, min(int(window_minutes or 5), 60))
    cutoff = datetime.now(timezone.utc) - timedelta(minutes=window_minutes)
    snap: Dict[str, Any] = {
        "window_minutes": window_minutes,
        "ts": datetime.now(timezone.utc).isoformat(),
        "memory": {},
        "mongo": {},
        "latency": {},
        "duplicates": {},
        "parser_health": {},
    }

    # ── Memory (process RSS) ─────────────────────────────────
    try:
        import resource
        rss_kb = resource.getrusage(resource.RUSAGE_SELF).ru_maxrss
        # ru_maxrss is in KB on Linux, bytes on macOS — assume Linux container
        snap["memory"]["rss_mb"] = round(rss_kb / 1024.0, 1)
    except Exception as _e:
        snap["memory"]["error"] = str(_e)

    try:
        import psutil  # type: ignore
        p = psutil.Process()
        mi = p.memory_info()
        snap["memory"]["rss_mb_psutil"] = round(mi.rss / (1024 * 1024), 1)
        snap["memory"]["vms_mb_psutil"] = round(mi.vms / (1024 * 1024), 1)
        snap["memory"]["cpu_pct"] = round(p.cpu_percent(interval=0.05), 1)
    except Exception:
        pass  # psutil optional

    # ── Mongo collection sizes + recent growth ───────────────
    try:
        collections_of_interest = [
            "vin_data", "vin_data_westmotors", "vin_data_lemon",
            "promotion_runs", "westmotors_sync_runs", "lemon_sync_runs",
            "audit_events", "errors_log", "slow_query_log",
        ]
        present = set(await db.list_collection_names())
        coll_stats: List[Dict[str, Any]] = []
        for cname in collections_of_interest:
            if cname not in present:
                continue
            try:
                cnt = await db[cname].count_documents({})
            except Exception:
                cnt = None
            block = {"collection": cname, "count": cnt}
            # Growth in window: count docs by `created_at` or `started_at`
            for ts_field in ("created_at", "started_at", "ts", "last_seen"):
                try:
                    grown = await db[cname].count_documents(
                        {ts_field: {"$gte": cutoff}}
                    )
                    if grown:
                        block[f"new_in_window_by_{ts_field}"] = grown
                        break
                except Exception:
                    continue
            coll_stats.append(block)
        snap["mongo"]["collections"] = coll_stats
    except Exception as _e:
        snap["mongo"]["error"] = str(_e)

    # ── Latency: average response times (recent slow_query_log) ──
    try:
        if "slow_query_log" in await db.list_collection_names():
            sq = await db.slow_query_log.find(
                {"ts": {"$gte": cutoff}}
            ).sort([("ts", -1)]).to_list(length=200)
            if sq:
                ds = [float(x.get("ms") or x.get("duration_ms") or 0) for x in sq]
                ds = [x for x in ds if x > 0]
                if ds:
                    snap["latency"]["slow_query_count"] = len(ds)
                    snap["latency"]["slow_avg_ms"] = round(sum(ds) / len(ds), 1)
                    snap["latency"]["slow_max_ms"] = round(max(ds), 1)
    except Exception:
        pass

    # ── Duplicate / promotion explosion check ────────────────
    try:
        agg_dupes = 0
        agg_runs = 0
        cursor = db.promotion_runs.find({"started_at": {"$gte": cutoff}})
        async for r in cursor:
            agg_runs += 1
            for s in r.get("results") or []:
                agg_dupes += int(s.get("duplicates") or 0)
        snap["duplicates"] = {
            "promotion_runs_in_window": agg_runs,
            "duplicates_seen": agg_dupes,
        }
    except Exception:
        pass

    # ── Parser worker health (timeouts, bans, blacklist) ─────
    try:
        ph: Dict[str, Any] = {}
        if WESTMOTORS_PARSER_AVAILABLE and westmotors_parser_instance:
            st = await westmotors_parser_instance.get_stats()
            ph["westmotors"] = {
                "parsed": st.get("db", {}).get("parsed"),
                "unparsed": st.get("db", {}).get("unparsed"),
                "blacklisted": st.get("db", {}).get("blacklisted"),
                "parsed_pct": st.get("db", {}).get("parsed_pct"),
                "counters": st.get("counters"),
            }
        if LEMON_AVAILABLE and lemon_sync_instance:
            st = await lemon_sync_instance.get_stats()
            ph["lemon"] = {
                "parsed": st.get("db", {}).get("parsed"),
                "unparsed": st.get("db", {}).get("unparsed"),
                "with_vin": st.get("db", {}).get("with_vin"),
                "with_lot": st.get("db", {}).get("with_lot"),
                "parsed_pct": st.get("db", {}).get("parsed_pct"),
                "worker_counters": st.get("worker_counters"),
            }
        snap["parser_health"] = ph
    except Exception as _e:
        snap["parser_health"]["error"] = str(_e)

    return {"success": True, "data": snap}


@fastapi_app.post("/api/ingestion/admin/parsers/run-all", dependencies=[Depends(require_master_admin)])
async def run_all_parsers(data: Dict[str, Any] = Body(default={})):
    """Start every runnable parser in a single click.

    Optional body:
      - ``max_pages`` (int)     — same cap propagated to bitmotors-class scrapers.
      - ``max_vehicles`` (int)  — soft cap → derived to pages.
      - ``run_once`` (bool)     — if true, also fires an immediate run_once() on
                                  each capable instance after starting the loop.

    Returns per-source status dict.
    """
    parser_config.enabled = True

    max_pages = int(data.get("max_pages") or 0)
    max_vehicles = int(data.get("max_vehicles") or 0)
    if max_vehicles and not max_pages:
        max_pages = max(1, (max_vehicles // 30) + 1)
    run_once_flag = bool(data.get("run_once", False))

    results: Dict[str, Any] = {}

    # bitmotors continuous loop + optional run_once
    if BITMOTORS_AVAILABLE and bitmotors_parser_instance:
        try:
            results["bitmotors"] = bitmotors_parser_instance.start()
            if run_once_flag and bitmotors_full_sync_instance:
                if max_pages and hasattr(bitmotors_full_sync_instance, "settings"):
                    bitmotors_full_sync_instance.settings["max_pages"] = max_pages
                results["bitmotors_full_sync_run"] = await bitmotors_full_sync_instance.run_once()
            elif run_once_flag and bitmotors_incremental_instance:
                results["bitmotors_incremental_run"] = await bitmotors_incremental_instance.run_once(pages=max_pages or None)
        except Exception as e:
            results["bitmotors"] = {"error": str(e)}

    if WESTMOTORS_AVAILABLE and westmotors_sync_instance:
        try:
            westmotors_sync_instance.start()
            results["westmotors"] = {"started": True}
            if run_once_flag:
                results["westmotors_run"] = await westmotors_sync_instance.run_incremental_sync()
        except Exception as e:
            results["westmotors"] = {"error": str(e)}

    if LEMON_AVAILABLE and lemon_sync_instance:
        try:
            lemon_sync_instance.start()
            results["lemon"] = {"started": True}
            if run_once_flag:
                if hasattr(lemon_sync_instance, "run_incremental_discovery"):
                    results["lemon_run"] = await lemon_sync_instance.run_incremental_discovery()
                elif hasattr(lemon_sync_instance, "run_incremental_sync"):
                    results["lemon_run"] = await lemon_sync_instance.run_incremental_sync()
        except Exception as e:
            results["lemon"] = {"error": str(e)}

    # Update registry status flags
    for src in ("bitmotors", "westmotors", "lemon", "carfast", "autoastat"):
        ent = PARSER_REGISTRY.get(src)
        if ent and ent.readiness == "ready":
            ent.enabled = True
            ent.status = "active"
            ent.last_run = datetime.now(timezone.utc).isoformat()

    return {
        "success": True,
        "message": "All parsers started",
        "max_pages": max_pages,
        "max_vehicles": max_vehicles,
        "ran_once": run_once_flag,
        "results": results,
    }

@fastapi_app.post("/api/ingestion/admin/parsers/stop-all", dependencies=[Depends(require_master_admin)])
async def stop_all_parsers():
    """Stop every parser in a single click."""
    parser_config.enabled = False

    results: Dict[str, Any] = {}
    if bitmotors_parser_instance:
        try:
            results["bitmotors"] = bitmotors_parser_instance.stop()
        except Exception as e:
            results["bitmotors"] = {"error": str(e)}
    if westmotors_sync_instance:
        try:
            westmotors_sync_instance.stop()
            results["westmotors"] = {"stopped": True}
        except Exception as e:
            results["westmotors"] = {"error": str(e)}
    if lemon_sync_instance:
        try:
            lemon_sync_instance.stop()
            results["lemon"] = {"stopped": True}
        except Exception as e:
            results["lemon"] = {"error": str(e)}

    for src in ("bitmotors", "westmotors", "lemon", "carfast", "autoastat"):
        ent = PARSER_REGISTRY.get(src)
        if ent:
            ent.enabled = False
            ent.status = "standby"

    return {"success": True, "message": "All parsers stopped", "results": results}

