async def _real_proxy_test(proxy: Dict[str, Any]) -> Dict[str, Any]:
    """Actually connect through the proxy and measure latency."""
    import time as _t
    url = proxy.get("url")
    if not url:
        return {"status": "error", "error": "no url"}
    try:
        import httpx
        start = _t.monotonic()
        async with httpx.AsyncClient(proxies=url, timeout=10) as client:
            r = await client.get("https://api.ipify.org?format=json")
            latency = int((_t.monotonic() - start) * 1000)
            return {"status": "ok" if r.status_code == 200 else "error",
                    "latency": latency, "http_status": r.status_code}
    except Exception as e:
        return {"status": "error", "error": str(e)[:120]}

@fastapi_app.post("/api/ingestion/admin/proxies/{proxy_id}/test", dependencies=[Depends(require_admin)])
async def test_proxy(proxy_id: str):
    """Real connectivity test through the stored proxy."""
    proxy = await db.scraper_proxies.find_one({"id": proxy_id}, {"_id": 0})
    if not proxy:
        raise HTTPException(404, "Proxy not found")
    result = await _real_proxy_test(proxy)
    await db.scraper_proxies.update_one({"id": proxy_id}, {"$set": {"last_test": {**result, "at": datetime.now(timezone.utc).isoformat()}}})
    return {"success": result.get("status") == "ok", "result": result}

@fastapi_app.post("/api/ingestion/admin/proxies/test", dependencies=[Depends(require_admin)])
async def test_all_proxies():
    """Real connectivity test across all stored proxies."""
    proxies = await db.scraper_proxies.find({}, {"_id": 0}).to_list(length=200)
    results = []
    for p in proxies:
        r = await _real_proxy_test(p)
        results.append({"id": p.get("id"), **r})
        await db.scraper_proxies.update_one({"id": p.get("id")}, {"$set": {"last_test": {**r, "at": datetime.now(timezone.utc).isoformat()}}})
    return {"success": True, "results": results, "total": len(results)}

