@fastapi_app.get("/api/source-health")
async def source_health():
    """Real data-source health.

    VIN/data providers are reported from live provider_stats (success score
    + tier). Scraper sources (Copart/IAAI/Carfast) are reported by their real
    configured/enabled state — NOT fake latency. Sources that require cookies
    or a connected domain show 'needs_config' until wired in production.
    """
    sources: List[Dict[str, Any]] = []
    # 1) Live VIN provider health (real scores from provider_stats)
    try:
        _ps = _ps_service_or_503()
        for p in await _ps.service.list_all():
            score = p.get("score")
            status = "unknown"
            if isinstance(score, (int, float)):
                status = "healthy" if score >= 70 else ("degraded" if score >= 40 else "down")
            name = (p.get("provider_id") or p.get("providerId") or p.get("id")
                    or p.get("name") or p.get("manager_id") or p.get("managerId"))
            if not name:
                continue
            sources.append({
                "name": name,
                "type": "vin_provider",
                "status": status,
                "score": score,
                "tier": p.get("tier"),
                "lastCheck": p.get("updated_at") or p.get("last_event_at"),
            })
    except Exception:
        pass
    # 2) Scraper sources — honest enabled/needs_config state from real config
    try:
        scraper_enabled = bool(getattr(parser_config, "enabled", False))
    except Exception:
        scraper_enabled = False
    sources.append({
        "name": "Carfast", "type": "scraper",
        "status": "enabled" if scraper_enabled else "needs_config",
        "lastCheck": datetime.now(timezone.utc).isoformat(),
    })
    return {"success": True, "sources": sources, "total": len(sources)}

