@fastapi_app.get("/api/manager-ai/lead/{lead_id}")
async def manager_ai_lead(lead_id: str):
    """Rule-based lead insights: applies the scoring engine to the real lead
    record and derives deterministic next-step recommendations. (No mock AI.)"""
    from app.services import rules_engine as _re
    lead = await db.leads.find_one({"id": lead_id}, {"_id": 0})
    if not lead:
        raise HTTPException(404, "Lead not found")
    scoring = await _re.evaluate_entity_score(db, lead, "lead_score")
    recs: List[str] = []
    status = (lead.get("status") or "").lower()
    if not (lead.get("first_contact_at") or lead.get("last_contact_at")):
        recs.append("Make first contact — lead has no logged outreach yet")
    if status in ("new", "", "contacted"):
        recs.append("Qualify the lead and move it forward in the pipeline")
    if lead.get("source") == "referral":
        recs.append("Referral lead — prioritise, higher close probability")
    if not recs:
        recs.append("Keep nurturing — follow up within 24h")
    return {"success": True, "insights": {
        "score": scoring["score"],
        "matched_rules": scoring["matched_rules"],
        "recommendation": recs[0],
        "recommendations": recs,
    }}

@fastapi_app.get("/api/manager-ai/user/{user_id}")
async def manager_ai_user(user_id: str):
    """Rule-based manager performance insights computed from real deals."""
    mq = {"$or": [{"managerId": user_id}, {"manager_id": user_id}]}
    total = await db.deals.count_documents(mq)
    won = await db.deals.count_documents({**mq, "stage": {"$in": ["closed_won", "delivered"]}})
    open_deals = await db.deals.count_documents({**mq, "stage": {"$nin": ["closed_won", "delivered", "cancelled", "closed_lost", "refunded", "lost", "closed"]}})
    win_rate = round(won / total, 3) if total else 0
    perf = "no_data" if total == 0 else ("strong" if win_rate >= 0.4 else ("average" if win_rate >= 0.2 else "needs_attention"))
    suggestions: List[str] = []
    if total and win_rate < 0.2:
        suggestions.append("Win-rate below 20% — review qualification & follow-up cadence")
    if open_deals > 8:
        suggestions.append(f"{open_deals} open deals — risk of overload, consider rebalancing")
    return {"success": True, "insights": {
        "performance": perf, "totalDeals": total, "wonDeals": won,
        "openDeals": open_deals, "winRate": win_rate, "suggestions": suggestions,
    }}

@fastapi_app.get("/api/deal-engine/evaluate")
async def deal_engine_evaluate(vin: Optional[str] = None, price: Optional[int] = None):
    """Rule-based deal evaluation from real comparable data + scoring engine.
    (No mock AI — deterministic heuristics over live listings.)"""
    from app.services import rules_engine as _re
    entity = {"value": price or 0, "vin": vin}
    scoring = await _re.evaluate_entity_score(db, entity, "deal_score")
    risks: List[str] = []
    recommendation = "insufficient_data"
    comp_count = 0
    if vin:
        existing = await db.vin_data.find_one({"vin": vin.upper()}, {"_id": 0, "price": 1})
        if not existing:
            risks.append("No VIN history found — verify the vehicle record")
    if price:
        # Compare against comparable listings' average price (real data)
        try:
            agg = await db.vin_data.aggregate([
                {"$match": {"price": {"$gt": 0}}},
                {"$group": {"_id": None, "avg": {"$avg": "$price"}, "n": {"$sum": 1}}},
            ]).to_list(length=1)
            if agg:
                avg = agg[0]["avg"]; comp_count = agg[0]["n"]
                if avg and price > avg * 1.25:
                    risks.append("Price ~25% above market average")
                    recommendation = "overpriced"
                elif avg and price < avg * 0.75:
                    recommendation = "good_deal"
                else:
                    recommendation = "fair"
        except Exception:
            pass
    return {"success": True, "evaluation": {
        "score": scoring["score"], "matched_rules": scoring["matched_rules"],
        "recommendation": recommendation, "comparables": comp_count, "risks": risks,
    }}


